import React, { useState, useEffect } from 'react';
import './App.css';

import companyLogo from './assets/logo.png';

interface Deployment {
  customer: string;
  project: string;
  environment: string;
  branch: string;
  commit: string;
  user: string;
  email: string;
  releaseDate: string;
  buildDate: string;
}

interface ApiResponse {
  pageNumber: number;
  pageSize: number;
  total: number;
  results: Deployment[];
}

// Updated interface to support history loading
interface CustomerGroup {
  customer: string;
  latest: Deployment;       // The single latest row
  history: Deployment[];    // Older rows (loaded on demand)
  isExpanded: boolean;
  historyLoaded: boolean;
  loadingHistory: boolean;
}

type Environment = 'PROD' | 'STAGE' | 'TEST';

// CONFIGURATION
const GITHUB_ORG = "keros-dev";
const GITHUB_REPO = "KNimbus-2017";

function App() {
  const [deployments, setDeployments] = useState<Deployment[]>([]);
  const [customerGroups, setCustomerGroups] = useState<CustomerGroup[]>([]);
  const [loading, setLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedEnv, setSelectedEnv] = useState<Environment>('PROD');

  // 1. Get the latest deployment per customer/project/environment
  const getLatestDeployments = (data: Deployment[]): Deployment[] => {
    const map = new Map<string, Deployment>();
    data.forEach((dep) => {
      // FIXED: Removed extra $ signs
      const key = `$${dep.customer}-$${dep.project}-${dep.environment}`;
      const existing = map.get(key);
      if (!existing || new Date(dep.releaseDate) > new Date(existing.releaseDate)) {
        map.set(key, dep);
      }
    });
    return Array.from(map.values());
  };

  // 2. Initialize groups with only the latest row
  const initializeGroups = (latestList: Deployment[]): CustomerGroup[] => {
    const map = new Map<string, Deployment[]>();

    // Group latest by customer
    latestList.forEach((dep) => {
      if (!map.has(dep.customer)) {
        map.set(dep.customer, []);
      }
      map.get(dep.customer)!.push(dep);
    });

    // Create group objects
    const result: CustomerGroup[] = Array.from(map.entries()).map(([customer, deps]) => {
      const sortedDeps = deps.sort(
        (a, b) => new Date(b.releaseDate).getTime() - new Date(a.releaseDate).getTime()
      );
      return {
        customer,
        latest: sortedDeps[0], // The absolute newest one
        history: [],           // Empty initially
        isExpanded: true,
        historyLoaded: false,
        loadingHistory: false
      };
    });

    return result.sort((a, b) => a.customer.localeCompare(b.customer));
  };

  // 3. Fetch initial data
  const fetchDeployments = async (env: Environment) => {
    try {
      setLoading(true);
      setError(null);
      const response = await fetch(`/release/all/${env}`);
      if (!response.ok) {
        throw new Error(`HTTP Error: ${response.status}`);
      }
      const data: ApiResponse = await response.json();
      setDeployments(data.results);

      const latestList = getLatestDeployments(data.results);
      setCustomerGroups(initializeGroups(latestList));
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Unknown error');
      console.error('Error fetching data:', err);
    } finally {
      setLoading(false);
    }
  };

  // 4. Load history for a specific customer
  const loadCustomerHistory = async (customerName: string) => {
    // Set loading state for this specific group
    setCustomerGroups(prev => prev.map(group => 
      group.customer === customerName ? { ...group, loadingHistory: true } : group
    ));

    try {
      // Fetch ALL data again (since API doesn't have a "by customer" endpoint)
      const response = await fetch(`/release/all/${selectedEnv}`);
      if (!response.ok) throw new Error(`HTTP Error: ${response.status}`);

      const data: ApiResponse = await response.json();

      // Filter for this customer
      const allForCustomer = data.results.filter(d => d.customer === customerName);

      // Re-calculate latest for this specific customer to know what to exclude
      const latestMap = new Map<string, Deployment>();
      allForCustomer.forEach(dep => {
        const key = `$${dep.project}-$${dep.environment}`;
        const existing = latestMap.get(key);
        if (!existing || new Date(dep.releaseDate) > new Date(existing.releaseDate)) {
          latestMap.set(key, dep);
        }
      });

      // Create a set of keys for the latest deployments to exclude them
      const latestKeys = new Set(latestMap.values().map(d => 
        `$${d.project}-$${d.environment}-${d.commit}`
      ));

      // Filter out the latest ones to get the history
      const history = allForCustomer
        .filter(dep => !latestKeys.has(`$${dep.project}-$${dep.environment}-${dep.commit}`))
        .sort((a, b) => new Date(b.releaseDate).getTime() - new Date(a.releaseDate).getTime());

      // Update state
      setCustomerGroups(prev => prev.map(group => {
        if (group.customer !== customerName) return group;
        return {
          ...group,
          history,
          historyLoaded: true,
          loadingHistory: false
        };
      }));

    } catch (err) {
      console.error('Error loading history:', err);
      setCustomerGroups(prev => prev.map(group => 
        group.customer === customerName ? { ...group, loadingHistory: false } : group
      ));
    }
  };

  const toggleCustomerGroup = (index: number) => {
    setCustomerGroups(prev => 
      prev.map((group, i) => 
        i === index ? { ...group, isExpanded: !group.isExpanded } : group
      )
    );
  };

  const toggleAllGroups = (expand: boolean) => {
    setCustomerGroups(prev => 
      prev.map(group => ({ ...group, isExpanded: expand }))
    );
  };

  const formatDate = (dateString: string) => {
    if (dateString === '0001-01-01T00:00:00') return '-';
    const date = new Date(dateString);
    const pad = (num: number) => num.toString().padStart(2, '0');
    return `$${date.getFullYear()}/$${pad(date.getMonth() + 1)}/${pad(date.getDate())} $${pad(date.getHours())}:$${pad(date.getMinutes())}`;
  };

  const getEnvironmentBadge = (env: string) => {
    const colors: Record<string, string> = {
      PROD: '#dc3545',
      STAGE: '#ffc107',
      TEST: '#28a745'
    };
    return colors[env] || '#6c757d';
  };

  const getGitHubUrl = (commitHash: string) => {
    return `https://github.com/$${GITHUB_ORG}/$${GITHUB_REPO}/commit/${commitHash}`;
  };

  return (
    <div className="App">
      <header className="App-header">
        <div className="header-title">
          <img 
            src={companyLogo} 
            alt="Company Logo" 
            className="app-logo" 
          />
          <h1>Deploy Tracker</h1>
        </div>
        <div className="controls">
          <label htmlFor="env-select">Environment:</label>
          <select 
            id="env-select" 
            value={selectedEnv} 
            onChange={handleEnvChange}
            disabled={loading}
          >
            <option value="PROD">PROD</option>
            <option value="STAGE">STAGE</option>
            <option value="TEST">TEST</option>
          </select>
          <button 
            onClick={() => fetchDeployments(selectedEnv)} 
            disabled={loading}
            className="refresh-btn"
          >
            {loading ? 'Loading...' : 'Refresh'}
          </button>
        </div>
      </header>

      <main className="App-main">
        {!loading && !error && (
          <div className="stats">
            <span>Customers: {customerGroups.length}</span>
            <div className="bulk-controls">
              <button onClick={() => toggleAllGroups(true)} className="bulk-btn">Expand All</button>
              <button onClick={() => toggleAllGroups(false)} className="bulk-btn">Collapse All</button>
            </div>
          </div>
        )}

        {loading && <div className="loading">Loading data...</div>}

        {error && <div className="error">❌ Error: {error}</div>}

        {!loading && !error && customerGroups.length === 0 && (
          <div className="no-data">No deployments found for {selectedEnv}</div>
        )}

        {!loading && !error && customerGroups.length > 0 && (
          <div className="grouped-table-container">
            {customerGroups.map((group, groupIndex) => (
              <div key={group.customer} className="customer-group">
                {/* Customer Header */}
                <div 
                  className="customer-header"
                  onClick={() => toggleCustomerGroup(groupIndex)}
                >
                  <span className={`toggle-icon ${group.isExpanded ? 'expanded' : 'collapsed'}`}>▶</span>
                  <span className="customer-name">{group.customer}</span>
                  <span className="deployment-count">
                    {group.historyLoaded 
                      ? `1 latest + ${group.history.length} older` 
                      : `1 latest deployment`}
                  </span>
                </div>

                {group.isExpanded && (
                  <>
                    {/* Latest Deployment Table */}
                    <table className="deployment-table">
                      <thead>
                        <tr>
                          <th>Project</th>
                          <th>Environment</th>
                          <th>Branch</th>
                          <th>Commit</th>
                          <th>Deployer</th>
                          <th>Release Date</th>
                        </tr>
                      </thead>
                      <tbody>
                        <tr>
                          <td>{group.latest.project}</td>
                          <td>
                            <span className="badge" style={{ backgroundColor: getEnvironmentBadge(group.latest.environment) }}>
                              {group.latest.environment}
                            </span>
                          </td>
                          <td>{group.latest.branch}</td>
                          <td className="commit">
                            <a href={getGitHubUrl(group.latest.commit)} target="_blank" rel="noopener noreferrer" className="commit-link">
                              {group.latest.commit.substring(0, 7)} ↗
                            </a>
                          </td>
                          <td>{group.latest.user}</td>
                          <td>{formatDate(group.latest.releaseDate)}</td>
                        </tr>
                      </tbody>
                    </table>

                    {/* History Section (Only if loaded) */}
                    {group.historyLoaded && group.history.length > 0 && (
                      <div className="history-section">
                        <h4 className="history-title">Older Deployments</h4>
                        <table className="deployment-table history-table">
                          <thead>
                            <tr>
                              <th>Project</th>
                              <th>Environment</th>
                              <th>Branch</th>
                              <th>Commit</th>
                              <th>Deployer</th>
                              <th>Release Date</th>
                            </tr>
                          </thead>
                          <tbody>
                            {group.history.map((dep, idx) => (
                              <tr key={`$${group.customer}-hist-$${idx}`}>
                                <td>{dep.project}</td>
                                <td>
                                  <span className="badge" style={{ backgroundColor: getEnvironmentBadge(dep.environment) }}>
                                    {dep.environment}
                                  </span>
                                </td>
                                <td>{dep.branch}</td>
                                <td className="commit">
                                  <a href={getGitHubUrl(dep.commit)} target="_blank" rel="noopener noreferrer" className="commit-link">
                                    {dep.commit.substring(0, 7)} ↗
                                  </a>
                                </td>
                                <td>{dep.user}</td>
                                <td>{formatDate(dep.releaseDate)}</td>
                              </tr>
                            ))}
                          </tbody>
                        </table>
                      </div>
                    )}

                    {/* Load History Button (Only if not loaded) */}
                    {!group.historyLoaded && (
                      <div className="load-history-container">
                        <button 
                          onClick={() => loadCustomerHistory(group.customer)}
                          disabled={group.loadingHistory}
                          className="load-history-btn"
                        >
                          {group.loadingHistory ? 'Loading...' : 'Load Older Deployments'}
                        </button>
                      </div>
                    )}
                  </>
                )}
              </div>
            ))}
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
